import json
from openai import OpenAI

client = OpenAI()

# Tools the agent can actually call
tools = [
    {
        "type": "function",
        "function": {
            "name": "search_flights",
            "description": "Search flights for a route and date range",
            "parameters": {
                "type": "object",
                "properties": {
                    "origin": {"type": "string"},
                    "destination": {"type": "string"},
                    "depart_after": {"type": "string", "description": "ISO date"},
                    "depart_before": {"type": "string", "description": "ISO date"},
                },
                "required": ["origin", "destination", "depart_after", "depart_before"]
            }
        }
    },
    {
        "type": "function",
        "function": {
            "name": "book_flight",
            "description": "Book a flight by flight ID",
            "parameters": {
                "type": "object",
                "properties": {"flight_id": {"type": "string"}},
                "required": ["flight_id"]
            }
        }
    }
]

# Mock tool executor
def execute_tool(name, args):
    if name == "search_flights":
        return [{"id": "NH803", "price": 620, "departs": "2026-07-07T10:00"}]
    if name == "book_flight":
        return {"confirmation": "XK-8821", "status": "confirmed"}

messages = [{"role": "user", "content": "Find cheapest flight to Tokyo next week from SFO and book it."}]

# Agent loop: keep going until model stops calling tools
while True:
    response = client.chat.completions.create(
        model="gpt-4o-mini",
        messages=messages,
        tools=tools,
    )
    msg = response.choices[0].message
    messages.append(msg)

    if not msg.tool_calls:
        # Model finished — no more tool calls
        print(msg.content)
        break

    for call in msg.tool_calls:
        result = execute_tool(call.function.name, json.loads(call.function.arguments))
        messages.append({
            "role": "tool",
            "tool_call_id": call.id,
            "content": json.dumps(result)
        })
# Final output: "I found flight NH803 departing July 7 at $620.
#                I have booked it. Confirmation: XK-8821."

# Minimal approval gate before a destructive tool call
def book_flight_with_approval(flight_id: str) -> dict:
    print(f"Agent wants to book flight {flight_id}. Approve? [y/n]: ", end="")
    if input().strip().lower() != "y":
        return {"status": "cancelled", "reason": "user declined"}
    return book_flight(flight_id)  # actual booking only after human confirms
